solution_code:
#include <iostream>

int clamp(int value, int lo, int hi) {
    return (value < lo) ? lo : (value > hi) ? hi : value;
}

int main() {
    int value, lo, hi;
    std::cin >> value >> lo >> hi;
    std::cout << clamp(value, lo, hi) << "\n";
    return 0;
}
